HRESULT MRFGreenProfile::GetGreenProfileName(CATUnicodeString &oName)
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnGreenProfile(_CredentialForGreenProfile, this);

	if ((!!FeatFacadeOnGreenProfile))//Check input
	{
		// Valuate attribute key
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValue;

		AttrKey = CATFmAttributeName(_MRFGreenProfileName);
		rc = FeatFacadeOnGreenProfile.GetValue(AttrKey, FmAttrValue);

		if (SUCCEEDED(rc))
		{
			FmAttrValue.GetString(oName);

		}
	}
	return rc;
}

HRESULT MRFGreenProfile::SetGreenProfileName(const CATUnicodeString iName)
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnGreenProfile(_CredentialForGreenProfile, this);

	if ((!!FeatFacadeOnGreenProfile))//Check input
	{
		// Valuate attribute key
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValue;

		AttrKey = CATFmAttributeName(_MRFGreenProfileName);
		FeatFacadeOnGreenProfile.UnsetValue(AttrKey);


		if (!!FeatFacadeOnGreenProfile)
		{
			FmAttrValue.Clear();
			FmAttrValue.SetString(iName);

			// Set the feature attribute
			rc = FeatFacadeOnGreenProfile.SetValue(AttrKey, FmAttrValue);
		}
	}
	return rc;
}

HRESULT MRFGreenProfile::SetXCordinatesList(const CATListOfDouble &iListXValues)
{
	int size = iListXValues.Size();
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnGreenProfile(_CredentialForGreenProfile, this);

	if ((size > 0) && (!!FeatFacadeOnGreenProfile))
	{
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValueOnXList;
		AttrKey = CATFmAttributeName(_MRFGreenProfileXList);
		FeatFacadeOnGreenProfile.UnsetValue(AttrKey);

		for (int i = 1; i <= size; i++)
		{
			double val = iListXValues[i];

			CATFmAttributeValue FmAttrValue;
			FmAttrValue.SetDouble(val);

			FmAttrValueOnXList.Append(FmAttrValue);
		}
		if (FmAttrValueOnXList.Size() > 0)
		{
			rc = FeatFacadeOnGreenProfile.SetValue(AttrKey, FmAttrValueOnXList);
		}
	}
	return rc;
}

